import os
from shutil import make_archive


def zip_files(filenames, output_path="output.zip"):
    # Ensure the output path ends with .zip
    if not output_path.endswith(".zip"):
        raise ValueError("Output must be a .zip file")

    # Ensure all filenames are valid and safe to zip
    for filename in filenames:
        if not os.path.isfile(filename):
            raise FileNotFoundError(f"{filename} does not exist or is not a file")
        if not filename.lower().endswith((".txt", ".pdf", ".docx", ".xls", ".ppt", ".png")):
            raise ValueError(f"Unsupported file type: {filename}")

    # Zip the files and return the path of the archive
    make_archive(output_path[:-4], "zip", output_path)
    return f"{output_path[:-4]}.zip"

